/**
 * Sample Library Catalog
 *
 * Auto-generated from public/samples/library/ directory.
 * Organizes 2300+ samples into categories for easy browsing.
 * Supports voice-aware filtering (e.g., kicks for KICK voice only).
 */

export interface LibrarySample {
  id: string;           // e.g. "eq-kick-001"
  name: string;         // e.g. "EQ Kick 001 - G#m"
  key: string;          // e.g. "G#m" (extracted from filename, may be empty)
  path: string;         // e.g. "/samples/library/kicks/eq-kick-001.ogg"
  category: SampleCategory;
  pack?: string;        // e.g. "kick" or "chord-slaps"
}

export type SampleCategory = 
  | "kicks" | "boom-kicks" | "snares" | "rims" | "claps" 
  | "hats-closed" | "hats-open" | "hats"
  | "cymbals" | "toms" | "percussions" | "shakers" | "snaps" | "sfx"
  | "chords" | "oneshots";

